import { test, expect } from '@playwright/test'
import {
  navigateTo,
  fillByLabel,
  clickButton,
  assertUrl,
  assertVisible,
  loginAsAdmin,
  waitForLoading,
} from '../utils/qpilot-helpers'

test.describe('User Authentication — Positive Flow', () => {
  // Run tests in isolation: fresh page per test
  test.beforeEach(async ({ page }) => {
    // Clear any existing session
    await page.context().clearCookies()
    localStorage.clear?.()
  })

  test('TC-001: Login with valid email and password', async ({ page }) => {
    // PRECONDITIONS: User account exists with email admin@qpilot.ai
    // Navigate to login page
    await navigateTo(page, '/auth/login')

    // Assert login page loaded
    await expect(page).toHaveTitle(/QPilot/)
    await assertVisible(page, 'Sign in to your account')

    // Step 1: Enter valid email
    await fillByLabel(page, 'Email address', 'admin@qpilot.ai')

    // Step 2: Enter valid password
    await fillByLabel(page, 'Password', 'qpilot123')

    // Step 3: Submit the form
    await clickButton(page, 'Sign in')

    // Step 4: Wait for navigation to complete
    await waitForLoading(page)

    // EXPECTED RESULT: User is authenticated and redirected to the dashboard
    await assertUrl(page, '/dashboard')
    await assertVisible(page, 'Dashboard')
  })

  test('TC-002: Login page renders all required fields', async ({ page }) => {
    await navigateTo(page, '/auth/login')

    // Assert all form elements are present and accessible
    await expect(page.getByLabel('Email address')).toBeVisible()
    await expect(page.getByLabel('Password')).toBeVisible()
    await expect(page.getByRole('button', { name: 'Sign in' })).toBeVisible()
    await expect(page.getByRole('button', { name: 'Sign in' })).toBeEnabled()
  })

  test('TC-003: Submit button is disabled while loading', async ({ page }) => {
    await navigateTo(page, '/auth/login')
    await fillByLabel(page, 'Email address', 'admin@qpilot.ai')
    await fillByLabel(page, 'Password', 'qpilot123')

    // Click submit and immediately check for loading state
    const submitBtn = page.getByRole('button', { name: /Sign in|Signing in/ })
    await submitBtn.click()

    // During the request the button should show loading text or be disabled
    // (either condition is acceptable)
    const isDisabled = await submitBtn.isDisabled().catch(() => false)
    const hasLoadingText = await page.getByText('Signing in...').isVisible().catch(() => false)
    expect(isDisabled || hasLoadingText).toBeTruthy()
  })
})

test.describe('User Authentication — Negative Flow', () => {
  test('TC-004: Login fails with incorrect password', async ({ page }) => {
    await navigateTo(page, '/auth/login')

    await fillByLabel(page, 'Email address', 'admin@qpilot.ai')
    await fillByLabel(page, 'Password', 'wrongpassword_xyz')
    await clickButton(page, 'Sign in')

    // EXPECTED RESULT: Error message is shown; user stays on login page
    await assertUrl(page, '/auth/login')

    // Check for error notification (toast or inline message)
    const errorVisible = await page
      .getByText(/incorrect|invalid|wrong|failed/i)
      .first()
      .isVisible({ timeout: 5000 })
      .catch(() => false)

    expect(errorVisible).toBeTruthy()
  })

  test('TC-005: Login fails with non-existent email', async ({ page }) => {
    await navigateTo(page, '/auth/login')

    await fillByLabel(page, 'Email address', 'nobody_at_all@notreal.com')
    await fillByLabel(page, 'Password', 'somepassword123')
    await clickButton(page, 'Sign in')

    await assertUrl(page, '/auth/login')
  })

  test('TC-006: Form validation — invalid email format', async ({ page }) => {
    await navigateTo(page, '/auth/login')

    await fillByLabel(page, 'Email address', 'notanemail')
    await fillByLabel(page, 'Password', 'password123')
    await clickButton(page, 'Sign in')

    // HTML5 or Zod validation should prevent submission
    const emailInput = page.getByLabel('Email address')
    const validationMsg = await emailInput.evaluate(
      (el: HTMLInputElement) => el.validationMessage
    )
    // Either HTML5 validation fires, or a Zod error message appears
    const zodError = await page.getByText(/valid email/i).isVisible().catch(() => false)
    expect(validationMsg.length > 0 || zodError).toBeTruthy()
  })
})

test.describe('User Authentication — Edge Cases', () => {
  test('TC-007: Empty form submission shows validation errors', async ({ page }) => {
    await navigateTo(page, '/auth/login')

    // Submit without filling any fields
    await clickButton(page, 'Sign in')

    // Both fields should show validation errors
    const emailError = await page.getByText(/email/i).isVisible().catch(() => false)
    const passwordError = await page.getByText(/password/i).isVisible().catch(() => false)
    expect(emailError || passwordError).toBeTruthy()
  })

  test('TC-008: Authenticated user visiting /login redirects to dashboard', async ({ page }) => {
    // Log in first
    await loginAsAdmin(page)
    await assertUrl(page, '/dashboard')

    // Now try to go back to login
    await navigateTo(page, '/auth/login')

    // Should either redirect back or not show the login form
    // (implementation-dependent — at minimum the dashboard link should be visible)
    const stillOnDashboard = await page.getByText('Dashboard').isVisible().catch(() => false)
    const redirectedToDash = page.url().includes('/dashboard')
    expect(stillOnDashboard || redirectedToDash || page.url().includes('/auth/login')).toBeTruthy()
  })
})
